-- -----------------------------------------------------
-- procedure add_account
-- -----------------------------------------------------
USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`add_account`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `add_account`(
    IN account_name VARCHAR(255),
    IN account_phone_number VARCHAR(20),
    IN account_password_hash BIGINT
)
BEGIN
    INSERT INTO accounts (Name, PhoneNumber, Balance, PasswordHash)
    VALUES (account_name, account_phone_number, 0, account_password_hash);
END$$

DELIMITER ;

