-- -----------------------------------------------------
-- procedure add_accounts_paypal_payment_methods
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`add_accounts_paypal_payment_methods`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `add_accounts_paypal_payment_methods`( IN account_id INT,
  IN paypal_id INT)
BEGIN
 IF account_id IS NULL OR paypal_id IS NULL THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'AccountID and PaypalID are required.';
END IF;

IF NOT EXISTS (SELECT 1 FROM accounts WHERE ID = account_id) THEN        
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Account does not exist.';
END IF;

IF NOT EXISTS (SELECT 1 FROM paypal_payment_methods WHERE ID = paypal_id) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Paypal payment method does not exist.';
END IF;

IF EXISTS (
	SELECT 1 FROM accounts_paypal_payment_methods
	WHERE AccountID = account_id AND PaypalID = paypal_id
) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Relation already exists.';
END IF;

INSERT INTO accounts_paypal_payment_methods (AccountID, PaypalID)
VALUES (account_id, paypal_id);
END$$

DELIMITER ;

-- -----------------------------------------------------
-- procedure add_card_payment_methods
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`add_card_payment_methods`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `add_card_payment_methods`(IN cardNumber VARCHAR(19)
)
BEGIN
IF cardNumber IS NULL OR TRIM(cardNumber) = '' THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Card number is required.';
END IF;

IF LENGTH(REPLACE(cardNumber, ' ', '')) < 12 OR LENGTH(REPLACE(cardNumber, ' ', '')) > 19 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Card number length is invalid.';
END IF;
 INSERT INTO card_payment_methods (CardNumber)
 VALUES (cardNumber);
END$$

DELIMITER ;

