-- -----------------------------------------------------
-- procedure add_customer_rentings
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`add_customer_rentings`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `add_customer_rentings`(IN account_id INT,
    IN movie_id INT,
    IN rental_days INT)
BEGIN
IF account_id IS NULL OR movie_id IS NULL OR rental_days IS NULL THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'CustomerID, MovieID and rental_days are required.';
END IF;

IF rental_days <= 0 THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'rental_days must be > 0.';
END IF;

IF NOT EXISTS (SELECT 1 FROM accounts WHERE ID = account_id) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Account does not exist.';
END IF;

IF NOT EXISTS (SELECT 1 FROM movies WHERE ID = movie_id) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Movie does not exist.';
END IF;

INSERT INTO customer_rentings (CustomerID, MovieID, PeriodStart, PeriodEnd, Price)
VALUES (account_id, movie_id, UNIX_TIMESTAMP(), UNIX_TIMESTAMP() + rental_days*24*60*60, get_movie_price_by_id(movie_id));
END$$

DELIMITER ;

