-- procedure add_movie
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`add_movie`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `add_movie`(  
IN movie_title VARCHAR(255), 
IN movie_runtime_seconds INT,
IN movie_minimum_age TINYINT,
IN movie_price DECIMAL(2,0),
IN movie_release_date DATE
)
BEGIN
  INSERT INTO movies (Title, RuntimeSeconds, MinimumAge, Price, ReleaseDate)
    VALUES (movie_title, movie_runtime_seconds, movie_minimum_age, movie_price, movie_release_date);
END$$

DELIMITER ;

-- -----------------------------------------------------
-- procedure add_movie_actors
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`add_movie_actors`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `add_movie_actors`(IN movie_id INT,
  IN person_id INT)
BEGIN
IF movie_id IS NULL OR person_id IS NULL THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'MovieID and ActorID are required.';
END IF;

IF NOT EXISTS (SELECT 1 FROM movies WHERE ID = movie_id) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Movie does not exist.';
END IF;

IF NOT EXISTS (SELECT 1 FROM people WHERE ID = person_id) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Actor does not exist.';
END IF;

IF EXISTS (SELECT 1 FROM movie_actors WHERE MovieID = movie_id AND PersonID = person_id) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Actor already linked to movie.';
END IF;

INSERT INTO movie_actors (MovieID, PersonID)
VALUES (movie_id, person_id);

END$$

DELIMITER ;

