-- -----------------------------------------------------
-- procedure add_order_with_orderline
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`add_order_with_orderline`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `add_order_with_orderline`(IN account_id INT,
    IN movie_id INT,
    IN giftcard_id INT,
	IN order_id INT)
BEGIN
DECLARE movie_price DECIMAL(19,2);
IF (movie_id IS NULL AND giftcard_id IS NULL)
	OR (movie_id IS NOT NULL AND giftcard_id IS NOT NULL) THEN
	SIGNAL SQLSTATE '45000'
	SET MESSAGE_TEXT = 'Order must have either MovieID or GiftcardID, but not both.';
END IF;

IF movie_id IS NOT NULL THEN
	SET movie_price = get_movie_price_by_id(movie_id);
ELSE
	SET movie_price = NULL;
END IF;

INSERT INTO orderlines (AccountID, MovieID, GiftcardID, OrderID, Price)
VALUES (account_id, movie_id, giftcard_id, order_id, movie_price);
END$$

DELIMITER ;

-- -----------------------------------------------------
-- procedure add_paypal_payment_methods
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`add_paypal_payment_methods`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `add_paypal_payment_methods`(IN Username VARCHAR(100),
    IN Email VARCHAR(120),
    IN Password VARCHAR(120)
    )
BEGIN
IF Username IS NULL OR TRIM(Username) = '' THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Paypal username is required.';
END IF;

IF Email IS NULL OR TRIM(Email) = '' THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Paypal email is required.';
END IF;

IF LOCATE('@', Email) = 0 THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Paypal email format is invalid.';
END IF;
 IF Password IS NULL OR TRIM(Password) = '' THEN
		SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Paypal password is required.';
    END IF;
    
 INSERT INTO paypal_payment_methods (Username, Email, Password)
 VALUES (Username, Email, Password);
END$$

