-- -----------------------------------------------------
-- procedure delete_account_by_id
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`delete_account_by_id`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `delete_account_by_id`(IN account_id INT)
BEGIN
IF account_id IS NULL OR account_id <= 0 THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'account_id must be a positive number.';
END IF;
IF NOT EXISTS (SELECT 1 FROM accounts WHERE ID = account_id) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Account not found.';
END IF;
CALL delete_account_card_relations_by_account_id(account_id);
CALL delete_account_paypal_relations_by_account_id(account_id);
CALL delete_customer_bookmarks_by_account_id(account_id);
CALL delete_customer_watchtracking_by_account_id(account_id);
CALL delete_customer_rentals_by_account_id(account_id);
CALL delete_support_tickets_by_account_id(account_id);
CALL delete_orderlines_by_account_id(account_id);
DELETE
FROM accounts
WHERE ID = account_id;
END$$

DELIMITER ;

