CALL delete_movie_spoken_languages_by_movie_id(movie_id);
CALL delete_movie_subtitle_languages_by_movie_id(movie_id);
CALL delete_customer_bookmarks_by_movie_id(movie_id);
CALL delete_customer_watchtracking_by_movie_id(movie_id);
CALL delete_customer_rentals_by_movie_id(movie_id);
CALL delete_orderlines_by_movie_id(movie_id);
DELETE
FROM movies
WHERE ID = movie_id;
END$$

