IN movie_min_age TINYINT, 
IN movie_min_price DECIMAL(2,0), 
IN movie_max_price DECIMAL(2,0))
BEGIN
SELECT * 
FROM movies 
WHERE MinimumAge <= movie_min_age 
AND Price BETWEEN movie_min_price AND movie_max_price;
END$$

