USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `get_movies_by_price_range`(IN movie_min_price DECIMAL(2,0),
    IN movie_max_price DECIMAL(2,0))
BEGIN
 SELECT *
 FROM movies
 WHERE Price BETWEEN movie_min_price AND movie_max_price;
END$$

