-- -----------------------------------------------------
-- procedure get_paypal_payment_methods_by_account_id
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`get_paypal_payment_methods_by_account_id`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `get_paypal_payment_methods_by_account_id`(IN account_id INT)
BEGIN
 SELECT ppm.*
 FROM paypal_payment_methods ppm
 JOIN accounts_paypal_payment_methods appm
 ON appm.PaypalID = ppm.ID
 WHERE appm.AccountID = account_id;
END$$

