-- -----------------------------------------------------
-- procedure get_paypal_payment_methods_by_id
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`get_paypal_payment_methods_by_id`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `get_paypal_payment_methods_by_id`(IN paypal_id INT)
BEGIN
IF paypal_id IS NULL OR paypal_id <= 0 THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'paypal_id must be a positive number.';
END IF;
IF NOT EXISTS (SELECT 1 FROM paypal_payment_methods WHERE ID = paypal_id) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Paypal payment method not found.';
END IF;

SELECT ID, Username, Email
FROM paypal_payment_methods
WHERE ID = paypal_id;
END$$

DELIMITER ;

