CREATE DEFINER=`root`@`%` PROCEDURE `get_publishers_by_movie_id`(IN movie_id INT)
BEGIN
IF movie_id IS NULL OR movie_id <= 0 THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'movie_id must be a positive number.';
END IF;
IF NOT EXISTS (SELECT 1 FROM movies WHERE ID = movie_id) THEN
	SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Movie not found.';
END IF;

SELECT publishers.*
FROM publishers
  JOIN movie_publishers 
  ON movie_publishers.PublisherID = publishers.ID
  WHERE movie_publishers.MovieID = movie_id;
END$$

