-- -----------------------------------------------------
-- procedure get_support_ticket_by_id
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`get_support_ticket_by_id`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `get_support_ticket_by_id`(IN ticket_id INT)
BEGIN
SELECT 
	st.ID,
	st.Title,
	st.Description,
	st.CreationDate,
	st.CreatedBy,
	a.Name AS CreatedByName
    FROM support_tickets st
    JOIN accounts a ON a.ID = st.CreatedBy
    WHERE st.ID = ticket_id;
END$$

DELIMITER ;

