-- -----------------------------------------------------
-- procedure update_account_by_id
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`update_account_by_id`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `update_account_by_id`(IN account_id INT,
    IN account_name VARCHAR(255),
    IN account_phone_number VARCHAR(20),
    IN account_balance DECIMAL(19,2),
    IN account_password BIGINT)
BEGIN
 UPDATE accounts
    SET 
    Name = COALESCE(NULLIF(account_name, ''), Name),
    PhoneNumber = COALESCE(NULLIF(account_phone_number, ''), PhoneNumber),
    Balance = COALESCE(account_balance, Balance),
    PasswordHash = COALESCE(NULLIF(account_password, ''), PasswordHash)
    WHERE ID = account_id;
END$$

DELIMITER ;

