CREATE DEFINER=`root`@`%` PROCEDURE `update_latest_watchtracking_by_customer_and_movie`(IN customer_id INT,
    IN movie_id INT,
    IN seconds_in_movie INT)
BEGIN
UPDATE customer_watchtracking
SET SecondsInMovie = COALESCE(seconds_in_movie, SecondsInMovie)
WHERE CustomerID = customer_id
AND MovieID = movie_id
ORDER BY TimeStamp DESC
LIMIT 1;
END$$

