-- -----------------------------------------------------
-- procedure update_movie_by_id
-- -----------------------------------------------------

USE `movie_rental_db`;
DROP procedure IF EXISTS `movie_rental_db`.`update_movie_by_id`;

DELIMITER $$
USE `movie_rental_db`$$
CREATE DEFINER=`root`@`%` PROCEDURE `update_movie_by_id`( 
	IN movie_id INT,
    IN movie_title VARCHAR(255),
    IN movie_runtime_seconds INT,
    IN movie_minimum_age TINYINT,
    IN movie_price DECIMAL(2,0),
    IN movie_release_date DATE)
BEGIN
 UPDATE movies
 SET
 Title          = COALESCE(movie_title, Title),
 RuntimeSeconds = COALESCE(movie_runtime_seconds, RuntimeSeconds),
 MinimumAge     = COALESCE(movie_minimum_age, MinimumAge),
 Price          = COALESCE(movie_price, Price),
 ReleaseDate    = COALESCE(movie_release_date, ReleaseDate)
 WHERE ID = movie_id;
END$$

DELIMITER ;

